import hashlib, json

def make_idempotency_key(record: dict) -> str:
    # Deterministic hash of the record's identifying fields
    content = json.dumps({
        "source": record["source"],
        "entity_id": record["entity_id"],
        "timestamp": record["timestamp"],
    }, sort_keys=True)
    return hashlib.sha256(content.encode()).hexdigest()

