VALID_TABLES = {"events", "users", "orders"}

def safe_delete_partition(engine, table: str, partition_date: str):
    if table not in VALID_TABLES:
        raise ValueError(f"Unknown table: {table}")
    with engine.begin() as conn:
        conn.execute(
            text(f"DELETE FROM {table} WHERE event_date = :date"),
            {"date": partition_date}
        )
